              <input 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && handleSend()}
                type="text" 
                placeholder="Escribe tu duda..." 
                className="flex-1 text-sm outline-none bg-gray-100 rounded-full px-4 py-2 focus:ring-1 focus:ring-[#6A00FF]"
              />
              <button onClick={handleSend} className="bg-[#6A00FF] text-white p-2 rounded-full hover:bg-purple-700">
                <Send size={16} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

