export const mockService = {
  // Auth
  login: async (email: string, pass: string): Promise<User> => {
    // TODO: POST /api/auth/login
    await new Promise(r => setTimeout(r, 800)); // Simulate latency
    const user = MOCK_USERS.find(u => u.email === email);
    if (user) return user;
    throw new Error("Credenciales inválidas");
  },

  // Products
  getProducts: async (filters?: any): Promise<Product[]> => {
    // TODO: GET /api/products?query parameters
    await new Promise(r => setTimeout(r, 500));
    let data = [...MOCK_PRODUCTS];
    if (filters?.category && filters.category !== 'Todos') {
      data = data.filter(p => p.genres.includes(filters.category) || p.platforms.includes(filters.category));
    }
    // Simulation of sorting for "New" or "Popular"
    if (filters?.sort === 'newest') {
      return data.sort((a, b) => b.id - a.id);
    }
    if (filters?.sort === 'popular') {
      return data.sort((a, b) => b.salesCount - a.salesCount);
    }
    if (filters?.sort === 'price_asc') {
      return data.sort((a, b) => a.priceUsd - b.priceUsd);
    }

    return data;
  },

  getProductById: async (id: number): Promise<Product | undefined> => {
    // TODO: GET /api/products/:id
    return MOCK_PRODUCTS.find(p => p.id === id);
  },

  // Orders
  createOrder: async (order: Partial<Order>): Promise<Order> => {
    // TODO: POST /api/orders
    await new Promise(r => setTimeout(r, 1000));
    return {
      id: Math.floor(Math.random() * 1000),
      userId: order.userId!,
      items: order.items!,
      totalUsd: order.totalUsd!,
      totalBs: order.totalBs!,
      status: 'pending',
      createdAt: new Date().toISOString()
