const ProductCard: React.FC<{ product: Product }> = ({ product }) => {
  const { currency, addToCart, toggleFavorite, favorites } = useStore();
  const navigate = useNavigate();
  const isFav = favorites.includes(product.id);

  return (
    <motion.div 
      whileHover={{ y: -5, scale: 1.02 }}
      className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full group"
    >
      <div className="relative h-64 overflow-hidden cursor-pointer" onClick={() => navigate(`/product/${product.id}`)}>
        <img src={product.images[0]} alt={product.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
        {product.stock <= 5 && <div className="absolute top-2 left-2"><Badge color="bg-red-500">Poco Stock</Badge></div>}
        <button 
          onClick={(e) => { e.stopPropagation(); toggleFavorite(product.id); }}
          className="absolute top-2 right-2 p-2 bg-white/80 rounded-full hover:bg-white text-gray-500 hover:text-red-500 transition-colors"
        >
          <Heart fill={isFav ? "currentColor" : "none"} className={isFav ? "text-red-500" : ""} size={18} />
        </button>
      </div>
      <div className="p-4 flex-1 flex flex-col">
        <div className="text-xs text-[#6A00FF] font-bold mb-1 uppercase">{product.genres[0]}</div>
        <h3 
          className="text-gray-900 font-bold text-lg mb-2 leading-tight cursor-pointer hover:text-[#6A00FF]"
          onClick={() => navigate(`/product/${product.id}`)}
        >
          {product.title}
        </h3>
        <div className="mt-auto flex items-center justify-between">
          <div className="flex flex-col">
            <span className="text-gray-400 text-xs line-through">
              {currency === 'USD' ? `$${(product.priceUsd * 1.2).toFixed(2)}` : `Bs ${(product.priceBs * 1.2).toFixed(2)}`}
            </span>
            <span className="text-xl font-bold text-gray-900">
              {currency === 'USD' ? `$${product.priceUsd}` : `Bs ${product.priceBs}`}
            </span>
          </div>
          <button 
            onClick={() => addToCart(product, 1)}
            disabled={product.stock === 0}
            className={`p-3 rounded-lg transition-colors ${product.stock === 0 ? 'bg-gray-200 cursor-not-allowed' : 'bg-[#6A00FF] text-white hover:bg-[#5b00db] active:scale-95'}`}
          >
            <ShoppingCart size={20} />
          </button>
        </div>
      </div>
    </motion.div>
  );
};

