      image: "https://images.unsplash.com/photo-1605901309584-818e25960b8f?ixlib=rb-1.2.1&auto=format&fit=crop&w=1950&q=80",
      title: "Next-Gen Gaming",
      subtitle: "Experimenta el verdadero poder gráfico con PlayStation 5 y Series X.",
      link: "/catalog?cat=Hardware",
      buttonText: "Ver Consolas"
    },
    {
