// --- SERVICE METHODS ---

export const mockService = {
  // Auth
  login: async (email: string, pass: string): Promise<User> => {
    // TODO: POST /api/auth/login
    await new Promise(r => setTimeout(r, 800)); // Simulate latency
    const user = MOCK_USERS.find(u => u.email === email);
    if (user) return user;
    throw new Error("Credenciales inválidas");
  },

  // Products
  getProducts: async (filters?: any): Promise<Product[]> => {
    // TODO: GET /api/products?query parameters
    await new Promise(r => setTimeout(r, 300));
    let data = [...MOCK_PRODUCTS];

    // Filter by Type (Game vs Console)
    if (filters?.type && filters.type !== 'all') {
      data = data.filter(p => p.type === filters.type);
    }

    // Filter by Genre
    if (filters?.genre && filters.genre !== 'Todos' && filters.genre !== '') {
      data = data.filter(p => p.genres.includes(filters.genre));
    }

    // Filter by Platform
    if (filters?.platform && filters.platform !== 'Todas' && filters.platform !== '') {
      data = data.filter(p => p.platforms.some(plat => plat.includes(filters.platform)));
    }

    // Filter by Mode
    if (filters?.mode && filters.mode !== 'Todos' && filters.mode !== '') {
      data = data.filter(p => p.modes.includes(filters.mode));
    }

    // Filter by Search (q)
    if (filters?.q) {
      const q = filters.q.toLowerCase();
      data = data.filter(p => p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q));
    }

    // Filter by Max Price
    if (filters?.priceMax) {
      data = data.filter(p => p.priceUsd <= filters.priceMax);
    }

    // Sorting
    if (filters?.sort) {
      switch (filters.sort) {
        case 'price_asc':
          data.sort((a, b) => a.priceUsd - b.priceUsd);
          break;
        case 'price_desc':
          data.sort((a, b) => b.priceUsd - a.priceUsd);
          break;
        case 'popularity':
          data.sort((a, b) => b.salesCount - a.salesCount);
          break;
        case 'name_asc':
          data.sort((a, b) => a.title.localeCompare(b.title));
          break;
        case 'name_desc':
          data.sort((a, b) => b.title.localeCompare(a.title));
          break;
        case 'date_desc':
          data.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
          break;
        case 'newest': // Fallback alias
          data.sort((a, b) => b.id - a.id);
          break;
      }
    }

    return data;
  },

  getProductById: async (id: number): Promise<Product | undefined> => {
    // TODO: GET /api/products/:id
    return MOCK_PRODUCTS.find(p => p.id === id);
  },

  // Orders
  createOrder: async (order: Partial<Order>): Promise<Order> => {
