  );
};

const ProductCarousel: React.FC<{ 
  title: string; 
  subtitle: string; 
  products: Product[]; 
  icon?: React.ElementType;
  linkTo?: string;
}> = ({ title, subtitle, products, icon: Icon, linkTo = "/catalog" }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { current } = scrollRef;
      const scrollAmount = direction === 'left' ? -340 : 340;
      current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
    }
  };

  return (
    <section className="max-w-7xl mx-auto px-4 py-12 border-b border-gray-50 last:border-0">
      <div className="flex justify-between items-end mb-8">
        <div>
          <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            {Icon && <Icon className="text-[#6A00FF]" />}
            {title}
          </h2>
          <p className="text-gray-500 mt-2">{subtitle}</p>
        </div>

        <div className="flex items-center gap-4">
          <Link to={linkTo} className="hidden sm:block text-[#6A00FF] font-semibold hover:underline">Ver todo</Link>
          <div className="flex gap-2">
            <button onClick={() => scroll('left')} className="p-2 rounded-full border border-gray-200 hover:bg-gray-50 text-gray-600">
              <ChevronLeft size={20} />
            </button>
            <button onClick={() => scroll('right')} className="p-2 rounded-full border border-gray-200 hover:bg-gray-50 text-gray-600">
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto snap-x snap-mandatory gap-6 pb-8 -mx-4 px-4 sm:px-0 scrollbar-hide"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {products.map(p => (
          <div key={p.id} className="min-w-[280px] sm:min-w-[300px] snap-start h-full">
            <ProductCard product={p} />
          </div>
        ))}
      </div>
    </section>
  );
};

