const ProductCard: React.FC<{ product: Product, viewMode?: 'grid' | 'list' }> = ({ product, viewMode = 'grid' }) => {
  const { currency, addToCart, toggleFavorite, favorites } = useStore();
  const navigate = useNavigate();
  const isFav = favorites.includes(product.id);

  if (viewMode === 'list') {
    return (
      <motion.div 
        whileHover={{ y: -2 }}
        className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-row h-48 group"
      >
        <div className="relative w-48 overflow-hidden cursor-pointer" onClick={() => navigate(`/product/${product.id}`)}>
          <img src={product.images[0]} alt={product.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
          {product.stock <= 5 && <div className="absolute top-2 left-2"><Badge color="bg-red-500">Poco Stock</Badge></div>}
        </div>
        <div className="p-6 flex-1 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start">
               <div>
                  <div className="text-xs text-[#6A00FF] font-bold mb-1 uppercase tracking-wide flex gap-2">
                    {product.type === 'game' ? 'Videojuego' : 'Consola'} • {product.genres[0]}
                  </div>
                  <h3 
                    className="text-gray-900 font-bold text-xl mb-2 cursor-pointer hover:text-[#6A00FF]"
                    onClick={() => navigate(`/product/${product.id}`)}
                  >
                    {product.title}
                  </h3>
               </div>
               <button 
                onClick={(e) => { e.stopPropagation(); toggleFavorite(product.id); }}
                className={`p-2 rounded-full hover:bg-gray-100 transition-colors ${isFav ? "text-red-500" : "text-gray-400"}`}
              >
                <Heart fill={isFav ? "currentColor" : "none"} size={20} />
              </button>
            </div>

            {/* Tags */}
            <div className="flex flex-wrap gap-2 mt-2">
               {product.platforms.map(p => <span key={p} className="text-[10px] bg-gray-100 px-2 py-1 rounded text-gray-600 border border-gray-200">{p}</span>)}
               {product.modes.map(m => <span key={m} className="text-[10px] bg-purple-50 px-2 py-1 rounded text-purple-700 border border-purple-100">{m}</span>)}
            </div>
          </div>

          <div className="flex items-center justify-between mt-4">
             <div className="flex flex-col">
                <span className="text-gray-400 text-xs line-through">
                  {currency === 'USD' ? `$${(product.priceUsd * 1.2).toFixed(2)}` : `Bs ${(product.priceBs * 1.2).toFixed(2)}`}
                </span>
                <span className="text-2xl font-bold text-gray-900">
                  {currency === 'USD' ? `$${product.priceUsd}` : `Bs ${product.priceBs}`}
                </span>
             </div>
             <button 
                onClick={() => addToCart(product, 1)}
                disabled={product.stock === 0}
                className={`px-6 py-3 rounded-lg font-bold flex items-center gap-2 transition-colors ${product.stock === 0 ? 'bg-gray-200 cursor-not-allowed' : 'bg-[#6A00FF] text-white hover:bg-[#5b00db] active:scale-95'}`}
              >
                <ShoppingCart size={18} /> Agregar
              </button>
          </div>
        </div>
      </motion.div>
    );
  }

  // Grid View
  return (
    <motion.div 
      whileHover={{ y: -5, scale: 1.02 }}
      className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full group"
    >
      <div className="relative h-64 overflow-hidden cursor-pointer" onClick={() => navigate(`/product/${product.id}`)}>
        <img src={product.images[0]} alt={product.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
        {product.stock <= 5 && <div className="absolute top-2 left-2"><Badge color="bg-red-500">Poco Stock</Badge></div>}
        <button 
          onClick={(e) => { e.stopPropagation(); toggleFavorite(product.id); }}
          className="absolute top-2 right-2 p-2 bg-white/80 rounded-full hover:bg-white text-gray-500 hover:text-red-500 transition-colors"
        >
          <Heart fill={isFav ? "currentColor" : "none"} className={isFav ? "text-red-500" : ""} size={18} />
        </button>
      </div>
      <div className="p-4 flex-1 flex flex-col">
        <div className="text-xs text-[#6A00FF] font-bold mb-1 uppercase flex flex-wrap gap-1">
           <span>{product.genres[0]}</span>
        </div>
        <h3 
          className="text-gray-900 font-bold text-lg mb-2 leading-tight cursor-pointer hover:text-[#6A00FF]"
          onClick={() => navigate(`/product/${product.id}`)}
        >
          {product.title}
        </h3>

        {/* Mini Tags */}
        <div className="flex flex-wrap gap-1 mb-3">
          {product.platforms.slice(0, 2).map(p => <span key={p} className="text-[10px] bg-gray-100 px-1.5 py-0.5 rounded text-gray-500">{p}</span>)}
