            </span>
            <span className="text-xl font-bold text-gray-900">
              {currency === 'USD' ? `$${product.priceUsd}` : `Bs ${product.priceBs}`}
            </span>
          </div>
          <button 
            onClick={() => addToCart(product, 1)}
            disabled={product.stock === 0}
            className={`p-3 rounded-lg transition-colors ${product.stock === 0 ? 'bg-gray-200 cursor-not-allowed' : 'bg-[#6A00FF] text-white hover:bg-[#5b00db] active:scale-95'}`}
          >
            <ShoppingCart size={20} />
          </button>
        </div>
      </div>
    </motion.div>
  );
};

const HeroCarousel: React.FC = () => {
