                  <h3 
                    className="text-gray-900 font-bold text-xl mb-2 cursor-pointer hover:text-[#6A00FF]"
                    onClick={() => navigate(`/product/${product.id}`)}
                  >
                    {product.title}
                  </h3>
               </div>
               <button 
                onClick={(e) => { e.stopPropagation(); toggleFavorite(product.id); }}
                className={`p-2 rounded-full hover:bg-gray-100 transition-colors ${isFav ? "text-red-500" : "text-gray-400"}`}
              >
                <Heart fill={isFav ? "currentColor" : "none"} size={20} />
              </button>
            </div>

            {/* Tags */}
            <div className="flex flex-wrap gap-2 mt-2">
               {product.platforms.map(p => <span key={p} className="text-[10px] bg-gray-100 px-2 py-1 rounded text-gray-600 border border-gray-200">{p}</span>)}
               {product.modes.map(m => <span key={m} className="text-[10px] bg-purple-50 px-2 py-1 rounded text-purple-700 border border-purple-100">{m}</span>)}
