             <button 
                onClick={() => addToCart(product, 1)}
                disabled={product.stock === 0}
                className={`px-6 py-3 rounded-lg font-bold flex items-center gap-2 transition-colors ${product.stock === 0 ? 'bg-gray-200 cursor-not-allowed' : 'bg-[#6A00FF] text-white hover:bg-[#5b00db] active:scale-95'}`}
              >
                <ShoppingCart size={18} /> Agregar
              </button>
