              </button>
            </div>

            {/* Tags */}
            <div className="flex flex-wrap gap-2 mt-2">
               {product.platforms.map(p => <span key={p} className="text-[10px] bg-gray-100 px-2 py-1 rounded text-gray-600 border border-gray-200">{p}</span>)}
