              className="max-w-2xl"
            >
              <Badge color="bg-[#6A00FF]">Destacado</Badge>
              <h1 className="text-5xl md:text-7xl font-bold text-white mt-4 mb-6 leading-tight">
                {slides[current].title.split(' ').map((word, i) => (
                  <span key={i} className={i === slides[current].title.split(' ').length - 1 ? 'galaxy-text' : ''}>
                    {word} 
                  </span>
                ))}
              </h1>
              <p className="text-gray-300 text-lg mb-8 max-w-lg">
                {slides[current].subtitle}
              </p>
              <Link to={slides[current].link} className="inline-flex items-center gap-2 bg-[#6A00FF] text-white px-8 py-4 rounded-lg font-bold hover:bg-[#5b00db] transition-all hover:gap-4">
                {slides[current].buttonText} <ArrowRight size={20} />
              </Link>
            </motion.div>
          </div>
        </motion.div>
      </AnimatePresence>

      {/* Controls */}
      <button 
        onClick={prevSlide}
        className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-white/20 text-white backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity"
      >
        <ChevronLeft size={24} />
      </button>
      <button 
        onClick={nextSlide}
        className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-white/10 hover:bg-white/20 text-white backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity"
      >
        <ChevronRight size={24} />
      </button>

      {/* Dots */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2">
        {slides.map((_, idx) => (
          <button 
            key={idx}
            onClick={() => setCurrent(idx)}
            className={`w-3 h-3 rounded-full transition-all ${idx === current ? 'bg-[#6A00FF] w-8' : 'bg-gray-500 hover:bg-gray-400'}`}
          />
        ))}
      </div>
    </section>
  );
};

const ProductCarousel: React.FC<{ 
  title: string; 
  subtitle: string; 
  products: Product[]; 
  icon?: React.ElementType;
  linkTo?: string;
}> = ({ title, subtitle, products, icon: Icon, linkTo = "/catalog" }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { current } = scrollRef;
      const scrollAmount = direction === 'left' ? -340 : 340;
      current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
    }
  };

  return (
    <section className="max-w-7xl mx-auto px-4 py-12 border-b border-gray-50 last:border-0">
      <div className="flex justify-between items-end mb-8">
        <div>
          <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            {Icon && <Icon className="text-[#6A00FF]" />}
            {title}
          </h2>
          <p className="text-gray-500 mt-2">{subtitle}</p>
        </div>

        <div className="flex items-center gap-4">
          <Link to={linkTo} className="hidden sm:block text-[#6A00FF] font-semibold hover:underline">Ver todo</Link>
          <div className="flex gap-2">
            <button onClick={() => scroll('left')} className="p-2 rounded-full border border-gray-200 hover:bg-gray-50 text-gray-600">
              <ChevronLeft size={20} />
            </button>
            <button onClick={() => scroll('right')} className="p-2 rounded-full border border-gray-200 hover:bg-gray-50 text-gray-600">
              <ChevronRight size={20} />
            </button>
          </div>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto snap-x snap-mandatory gap-6 pb-8 -mx-4 px-4 sm:px-0 scrollbar-hide"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {products.map(p => (
          <div key={p.id} className="min-w-[280px] sm:min-w-[300px] snap-start h-full">
            <ProductCard product={p} />
          </div>
        ))}
      </div>
    </section>
  );
};

