                        type="radio" 
                        name="mode" 
                        checked={mode === m} 
                        onChange={() => setMode(m)}
                        className="text-[#6A00FF] focus:ring-[#6A00FF] rounded-full"
                      />
                      <span className="text-sm text-gray-600">{m}</span>
                   </label>
                 ))}
                 <label className="flex items-center gap-2 cursor-pointer">
                    <input type="radio" name="mode" checked={mode === ''} onChange={() => setMode('')} className="text-[#6A00FF]" />
