export const FavoritesPage: React.FC = () => {
  const { favorites } = useStore();
  const [favProducts, setFavProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const loadFavorites = async () => {
      // Optimization: Only fetch if we have favorites
      if (favorites.length === 0) {
        setFavProducts([]);
        setLoading(false);
        return;
      }

      // Fetch details for each ID
      // In a real backend, we'd use GET /products?ids=1,2,3
      const promises = favorites.map(id => mockService.getProductById(id));
      const results = await Promise.all(promises);
      // Filter out undefined results
      setFavProducts(results.filter((p): p is Product => !!p));
      setLoading(false);
    };

    loadFavorites();
  }, [favorites]); // Re-run when favorites change

  return (
    <div className="max-w-7xl mx-auto px-4 py-12 min-h-[60vh]">
      <div className="flex items-center gap-3 mb-8">
        <Heart className="text-[#6A00FF] w-8 h-8 fill-current" />
        <h1 className="text-3xl font-bold text-gray-900">Mis Favoritos</h1>
      </div>

      {loading ? (
        <div className="text-center py-20">Cargando tus juegos guardados...</div>
      ) : favProducts.length === 0 ? (
        <div className="text-center py-20 bg-gray-50 rounded-2xl border border-dashed border-gray-200 flex flex-col items-center">
          <div className="bg-white p-6 rounded-full shadow-sm mb-6">
            <HeartCrack className="w-12 h-12 text-gray-300" />
          </div>
          <h2 className="text-xl font-bold text-gray-900 mb-2">Tu lista de deseos está vacía</h2>
          <p className="text-gray-500 mb-8 max-w-md">Parece que aún no has guardado nada. ¡Explora nuestro catálogo y guarda lo que te guste para después!</p>
          <Link 
            to="/catalog" 
            className="bg-[#6A00FF] text-white px-8 py-3 rounded-lg font-bold hover:bg-[#5b00db] transition-all flex items-center gap-2"
          >
            Explorar Catálogo <ArrowRight size={18} />
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <AnimatePresence>
            {favProducts.map(p => (
              <ProductCard key={p.id} product={p} viewMode="grid" />
            ))}
          </AnimatePresence>
        </div>
      )}
    </div>
  );
};

