                  <div className="font-semibold">{item.qty}</div>
                </div>
                <div className="font-bold text-[#6A00FF] w-24 text-right">
                  {currency === 'USD' ? `$${(item.product.priceUsd * item.qty).toFixed(2)}` : `Bs ${(item.product.priceBs * item.qty).toFixed(2)}`}
                </div>
                <button onClick={() => removeFromCart(item.productId)} className="text-gray-400 hover:text-red-500">
                  <Trash2 size={20} />
                </button>
              </div>
            </div>
          ))}
        </div>

        <div className="bg-gray-50 p-6 rounded-xl h-fit">
          <h3 className="font-bold text-lg mb-4">Total del Pedido</h3>
          <div className="flex justify-between mb-2">
            <span className="text-gray-600">Subtotal</span>
            <span className="font-semibold">{currency === 'USD' ? `$${cartTotalUsd.toFixed(2)}` : `Bs ${cartTotalBs.toFixed(2)}`}</span>
          </div>
          <div className="flex justify-between mb-4 pb-4 border-b">
            <span className="text-gray-600">Envío</span>
            <span className="font-semibold text-green-600">Gratis</span>
          </div>
          <div className="flex justify-between mb-6">
            <span className="font-bold text-xl">Total</span>
            <span className="font-bold text-xl text-[#6A00FF]">
              {currency === 'USD' ? `$${cartTotalUsd.toFixed(2)}` : `Bs ${cartTotalBs.toFixed(2)}`}
            </span>
          </div>
          <button 
            onClick={() => {
                // If user is admin, block purchase
                if(user?.role === 'admin') {
                   alert("Modo Administrador: No puedes realizar compras.");
                   return;
                }
                // Allow guests (no user) or customers
                setStep(1);
                setPaymentModalOpen(true);
            }}
            className="w-full bg-[#6A00FF] text-white py-4 rounded-lg font-bold hover:bg-[#5b00db] transition-colors flex justify-center items-center gap-2"
          >
             <CreditCard size={20} /> Proceder al Pago
          </button>
          <p className="text-xs text-gray-500 text-center mt-4">Transacciones seguras y encriptadas.</p>
        </div>
      </div>

      {/* PAYMENT MODAL */}
      <AnimatePresence>
        {isPaymentModalOpen && (
          <>
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setPaymentModalOpen(false)}
              className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
            />
            <motion.div 
              initial={{ opacity: 0, scale: 0.95, y: 20 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95 }}
