                  <div className="space-y-6">
                     <p className="text-gray-500 text-sm">Elige cómo deseas realizar tu pago. El monto total es <strong className="text-gray-900">${cartTotalUsd.toFixed(2)}</strong> o <strong className="text-gray-900">Bs {cartTotalBs.toFixed(2)}</strong>.</p>

                     <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                        {PAYMENT_METHODS.map(m => (
                            <button 
                                key={m.id}
                                onClick={() => setSelectedMethod(m.id)}
                                className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${selectedMethod === m.id ? 'border-[#6A00FF] bg-purple-50 text-[#6A00FF]' : 'border-gray-200 hover:border-purple-200 text-gray-600'}`}
                            >
                                <m.icon size={24} />
                                <span className="text-xs font-bold">{m.name}</span>
                            </button>
                        ))}
                     </div>

                     {selectedMethod && (
                        <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="bg-gray-50 p-6 rounded-xl border border-gray-200">
                             <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">Datos para {PAYMENT_METHODS.find(p => p.id === selectedMethod)?.name}</h3>
                             <div className="space-y-3">
                                {Object.entries(PAYMENT_METHODS.find(p => p.id === selectedMethod)?.data || {}).map(([key, value]) => (
                                    <div key={key} className="flex justify-between items-center bg-white p-3 rounded-lg border border-gray-100">
                                        <div>
                                            <span className="text-xs text-gray-400 block uppercase">{key}</span>
                                            <span className="font-medium text-gray-800">{value}</span>
                                        </div>
                                        <button onClick={() => handleCopy(value)} className="text-[#6A00FF] hover:bg-purple-100 p-2 rounded-full" title="Copiar">
                                            <Copy size={16} />
                                        </button>
                                    </div>
                                ))}
                             </div>
                             <div className="mt-6 flex justify-end">
                                <button 
                                    onClick={handlePaymentMade}
                                    className="bg-[#6A00FF] text-white px-6 py-3 rounded-lg font-bold hover:bg-[#5b00db] flex items-center gap-2"
                                >
                                    Pago Realizado <ArrowRight size={18} />
                                </button>
                             </div>
                        </motion.div>
                     )}
                  </div>
                )}

                {/* STEP 2: UPLOAD PROOF */}
                {step === 2 && (
                   <div className="space-y-6">
                      <div className="flex items-center gap-4 bg-purple-50 p-4 rounded-xl text-[#6A00FF] text-sm font-medium">
                         <div className="bg-white p-2 rounded-full"><Banknote size={20} /></div>
                         Reportando pago para el método: {PAYMENT_METHODS.find(p => p.id === selectedMethod)?.name}
                      </div>

                      <div>
                          <label className="block text-sm font-bold text-gray-700 mb-2">Número de Referencia</label>
                          <input 
                             type="text" 
                             value={refNumber}
                             onChange={e => setRefNumber(e.target.value)}
                             className="w-full border border-gray-200 rounded-lg px-4 py-3 focus:ring-2 focus:ring-[#6A00FF] outline-none"
                             placeholder="Ej: 12345678"
                          />
                      </div>

                      <div>
                          <label className="block text-sm font-bold text-gray-700 mb-2">Comprobante de Pago (Captura)</label>
                          <div className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:bg-gray-50 transition-colors relative">
                              <input 
                                type="file" 
                                accept="image/*"
                                onChange={e => setProofFile(e.target.files?.[0] || null)}
                                className="absolute inset-0 opacity-0 cursor-pointer"
                              />
                              <Upload className="mx-auto text-gray-400 mb-2" />
                              <p className="text-sm text-gray-500">
                                  {proofFile ? <span className="text-[#6A00FF] font-bold">{proofFile.name}</span> : "Haz click o arrastra tu imagen aquí"}
                              </p>
                          </div>
                      </div>

                      <div className="flex gap-4 pt-4">
                          <button 
                            onClick={() => setStep(1)}
                            className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-100 rounded-lg"
                          >
                            Atrás
                          </button>
                          <button 
                            onClick={handleSubmitOrder}
                            disabled={isSubmitting}
                            className="flex-1 bg-[#6A00FF] text-white py-3 rounded-lg font-bold hover:bg-[#5b00db] flex justify-center items-center gap-2 disabled:opacity-70"
                          >
                             {isSubmitting ? 'Enviando...' : 'Enviar y Finalizar'}
                          </button>
                      </div>
                   </div>
                )}

              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

