                 className="p-2 border border-gray-200 rounded-lg text-sm bg-white focus:ring-1 focus:ring-[#6A00FF] outline-none text-gray-900"
               >
                 <option value="popularity">Popularidad</option>
                 <option value="price_asc">Precio: Menor a Mayor</option>
                 <option value="price_desc">Precio: Mayor a Menor</option>
                 <option value="name_asc">Nombre: A-Z</option>
                 <option value="name_desc">Nombre: Z-A</option>
                 <option value="date_desc">Lanzamiento</option>
               </select>

               {/* View Toggle */}
               <div className="flex border border-gray-200 rounded-lg overflow-hidden">
                 <button 
                   onClick={() => setViewMode('grid')}
                   className={`p-2 ${viewMode === 'grid' ? 'bg-gray-100 text-[#6A00FF]' : 'bg-white text-gray-400 hover:bg-gray-50'}`}
                 >
                   <LayoutGrid size={20} />
                 </button>
                 <div className="w-[1px] bg-gray-200"></div>
                 <button 
                   onClick={() => setViewMode('list')}
                   className={`p-2 ${viewMode === 'list' ? 'bg-gray-100 text-[#6A00FF]' : 'bg-white text-gray-400 hover:bg-gray-50'}`}
                 >
                   <ListIcon size={20} />
                 </button>
               </div>
            </div>
          </div>

          {/* Grid/List */}
          <div className={`grid gap-6 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3' : 'grid-cols-1'}`}>
            {products.map(p => <ProductCard key={p.id} product={p} viewMode={viewMode} />)}
          </div>

          {products.length === 0 && (
            <div className="text-center py-20 bg-gray-50 rounded-xl border border-dashed border-gray-200">
              <p className="text-gray-500">No se encontraron productos con estos filtros.</p>
              <button 
                onClick={() => { setType('all'); setGenre(''); setPlatform(''); setMode(''); setMaxPrice(1000); setSearch('') }}
                className="mt-2 text-[#6A00FF] font-semibold hover:underline"
              >
                Limpiar filtros
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

