        <div className="text-center py-20">Cargando tus juegos guardados...</div>
      ) : favProducts.length === 0 ? (
        <div className="text-center py-20 bg-gray-50 rounded-2xl border border-dashed border-gray-200 flex flex-col items-center">
          <div className="bg-white p-6 rounded-full shadow-sm mb-6">
            <HeartCrack className="w-12 h-12 text-gray-300" />
          </div>
          <h2 className="text-xl font-bold text-gray-900 mb-2">Tu lista de deseos está vacía</h2>
          <p className="text-gray-500 mb-8 max-w-md">Parece que aún no has guardado nada. ¡Explora nuestro catálogo y guarda lo que te guste para después!</p>
          <Link 
            to="/catalog" 
            className="bg-[#6A00FF] text-white px-8 py-3 rounded-lg font-bold hover:bg-[#5b00db] transition-all flex items-center gap-2"
          >
