export const AdminDashboard: React.FC = () => {
  const { user } = useStore();
  const navigate = useNavigate();
  const [metrics, setMetrics] = useState<any>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'discounts'>('dashboard');

  // Modal State
  const [showAddModal, setShowAddModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [newProd, setNewProd] = useState<Partial<Product>>({
    title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10,
    description: '', genres: [], platforms: [], modes: [], images: []
  });

  const loadData = async () => {
    const [m, p, n, o] = await Promise.all([
      mockService.getMetrics(),
      mockService.getProducts(),
      mockService.getNotifications(),
      mockService.getOrders()
    ]);
    setMetrics(m);
    setProducts(p);
    setNotifications(n);
    setOrders(o);
  };

  useEffect(() => {
    if (!user || user.role !== 'admin') {
      navigate('/login');
      return;
    }
    loadData();
  }, [user]);

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await mockService.addProduct(newProd);
      setShowAddModal(false);
      setNewProd({ title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10, description: '', genres: [], platforms: [], modes: [], images: [] });
      await loadData();
      alert("Producto agregado exitosamente.");
    } catch (err) {
      alert("Error al agregar producto.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const updateDiscount = async (id: number, discount: number) => {
    try {
      await mockService.updateProduct(id, { discount });
      await loadData();
    } catch (err) {
      alert("Error al actualizar descuento.");
    }
  };

  if (!metrics) return <div className="min-h-screen flex items-center justify-center text-gray-900 font-bold">Cargando Panel...</div>;

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 pb-20">
      <div className="max-w-7xl mx-auto px-4 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
            <h1 className="text-2xl font-bold text-gray-900">Admin Central</h1>
            <div className="flex bg-white rounded-xl p-1 border border-gray-200 shadow-sm overflow-x-auto">
                {['dashboard', 'orders', 'products', 'discounts'].map((tab) => (
                  <button 
                    key={tab}
                    onClick={() => setActiveTab(tab as any)} 
                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${activeTab === tab ? 'bg-[#6A00FF] text-white shadow-lg shadow-purple-200' : 'text-gray-500 hover:bg-gray-50'}`}
                  >
                    {tab === 'dashboard' ? 'Resumen' : tab === 'orders' ? 'Pedidos' : tab === 'products' ? 'Inventario' : 'Descuentos'}
                  </button>
                ))}
            </div>
        </div>

        {/* --- VIEWS --- */}

        {activeTab === 'dashboard' && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
            <MetricCard title="Productos" val={metrics.totalProducts} icon={Package} color="bg-purple-100 text-[#6A00FF]" />
            <MetricCard title="Usuarios" val={metrics.totalUsers} icon={Users} color="bg-blue-100 text-blue-600" />
            <MetricCard title="Ventas Mes" val={`$${metrics.monthlySales}`} icon={ChartBar} color="bg-green-100 text-green-600" />
            <MetricCard title="Stock Bajo" val={metrics.lowStock} icon={CircleAlert} color="bg-red-100 text-red-600" />
          </div>
