             <div className="flex justify-between items-start">
               <div>
                  <div className="text-[10px] text-[#6A00FF] font-black mb-1 uppercase tracking-widest flex gap-2">
                    {product.type === 'game' ? 'JUEGO' : 'HARDWARE'} • {product.genres[0]}
