/**
 * Implementación de ProductDetails corregida
 */
const ProductDetails: React.FC = () => {
  const { id } = useParams();
  const { currency, addToCart, toggleFavorite, favorites } = useStore();
  const [product, setProduct] = useState<Product | null>(null);
  const [qty, setQty] = useState(1);
  const navigate = useNavigate();

  useEffect(() => {
    if (id) {
      mockService.getProductById(Number(id)).then(p => p ? setProduct(p) : navigate('/catalog'));
    }
  }, [id, navigate]);

  if (!product) return <div className="min-h-screen flex items-center justify-center font-bold">Cargando...</div>;

  const isFav = favorites.includes(product.id);
  const hasDiscount = !!product.discount && product.discount > 0;
  const finalPriceUsd = hasDiscount ? (product.priceUsd * (1 - product.discount! / 100)) : product.priceUsd;
  const finalPriceBs = hasDiscount ? (product.priceBs * (1 - product.discount! / 100)) : product.priceBs;

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        <div className="rounded-3xl overflow-hidden bg-gray-100 aspect-square">
          <img src={product.images[0]} alt={product.title} className="w-full h-full object-cover" />
        </div>
        <div className="flex flex-col justify-center">
          <div className="text-xs font-black text-[#6A00FF] uppercase tracking-widest mb-2">
            {product.type} • {product.genres.join(', ')}
          </div>
          <h1 className="text-4xl font-black text-gray-900 mb-4">{product.title}</h1>
          <p className="text-gray-500 mb-8 leading-relaxed">{product.description}</p>

          <div className="flex items-center gap-4 mb-8">
            <div className="flex flex-col">
              {hasDiscount && (
                <span className="text-gray-400 line-through font-bold">
                  {currency === 'USD' ? `$${product.priceUsd.toFixed(2)}` : `Bs ${product.priceBs.toFixed(2)}`}
                </span>
              )}
              <span className="text-4xl font-black text-gray-900">
                {currency === 'USD' ? `$${finalPriceUsd.toFixed(2)}` : `Bs ${finalPriceBs.toFixed(2)}`}
              </span>
            </div>
            {hasDiscount && <Badge color="bg-red-500">-{product.discount}% OFF</Badge>}
          </div>

          <div className="flex items-center gap-6 mb-8">
            <div className="flex items-center border border-gray-200 rounded-2xl p-1">
              <button onClick={() => setQty(Math.max(1, qty - 1))} className="p-3 hover:bg-gray-100 rounded-xl transition-colors"><Minus size={18}/></button>
              <span className="w-12 text-center font-bold">{qty}</span>
              <button onClick={() => setQty(qty + 1)} className="p-3 hover:bg-gray-100 rounded-xl transition-colors"><Plus size={18}/></button>
            </div>
            <button 
              onClick={() => addToCart(product, qty)}
              className="flex-1 bg-[#6A00FF] text-white py-4 rounded-2xl font-bold hover:bg-[#5b00db] transition-all flex items-center justify-center gap-2 shadow-xl shadow-purple-100"
            >
              <ShoppingCart size={20} /> Añadir al Carrito
            </button>
            <button 
              onClick={() => toggleFavorite(product.id)}
              className={`p-4 rounded-2xl border transition-all ${isFav ? 'bg-red-50 border-red-100 text-red-500' : 'bg-white border-gray-200 text-gray-400 hover:text-red-500'}`}
            >
              <Heart fill={isFav ? "currentColor" : "none"} size={24} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

