  useEffect(() => {
    if (id) {
      mockService.getProductById(Number(id)).then(p => p ? setProduct(p) : navigate('/catalog'));
    }
  }, [id, navigate]);

  if (!product) return <div className="min-h-screen flex items-center justify-center font-bold">Cargando...</div>;

  const isFav = favorites.includes(product.id);
  const hasDiscount = !!product.discount && product.discount > 0;
  const finalPriceUsd = hasDiscount ? (product.priceUsd * (1 - product.discount! / 100)) : product.priceUsd;
  const finalPriceBs = hasDiscount ? (product.priceBs * (1 - product.discount! / 100)) : product.priceBs;

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-start">
        <div className="rounded-[40px] overflow-hidden bg-gray-100 aspect-square shadow-2xl shadow-purple-50 border border-gray-100">
          <img src={product.images[0]} alt={product.title} className="w-full h-full object-cover" />
        </div>
        <div className="flex flex-col pt-2">
          <div className="text-xs font-black text-[#6A00FF] uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
            <Badge color="bg-[#6A00FF]">{product.type}</Badge> {product.genres.join(' • ')}
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 leading-tight">{product.title}</h1>
          <p className="text-gray-500 mb-10 text-lg leading-relaxed">{product.description}</p>

          <div className="flex items-center gap-6 mb-10">
            <div className="flex flex-col">
              {hasDiscount && (
                <span className="text-gray-400 line-through font-bold text-lg">
                  {currency === 'USD' ? `$${product.priceUsd.toFixed(2)}` : `Bs ${product.priceBs.toFixed(2)}`}
                </span>
              )}
              <span className="text-5xl font-black text-gray-900">
                {currency === 'USD' ? `$${finalPriceUsd.toFixed(2)}` : `Bs ${finalPriceBs.toFixed(2)}`}
              </span>
            </div>
            {hasDiscount && <div className="bg-red-500 text-white px-3 py-1 rounded-full font-black text-sm animate-pulse">-{product.discount}% DTO</div>}
          </div>

          <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center border-2 border-gray-100 rounded-2xl p-1 bg-white">
              <button 
                onClick={() => setQty(Math.max(1, qty - 1))} 
                className="p-3 text-[#6A00FF] hover:bg-purple-50 rounded-xl transition-all"
              >
                <Minus size={20} strokeWidth={3} />
              </button>
              <span className="w-14 text-center font-black text-black text-xl">{qty}</span>
              <button 
                onClick={() => setQty(qty + 1)} 
                className="p-3 text-[#6A00FF] hover:bg-purple-50 rounded-xl transition-all"
              >
                <Plus size={20} strokeWidth={3} />
              </button>
            </div>
            <button 
              onClick={() => addToCart(product, qty)}
              className="flex-1 min-w-[200px] bg-[#6A00FF] text-white py-5 rounded-2xl font-black text-lg hover:bg-[#5b00db] transition-all flex items-center justify-center gap-3 shadow-xl shadow-purple-200 active:scale-95"
            >
              <ShoppingCart size={22} /> Añadir al Carrito
            </button>
            <button 
              onClick={() => toggleFavorite(product.id)}
              className={`p-5 rounded-2xl border-2 transition-all active:scale-90 ${isFav ? 'bg-red-50 border-red-100 text-red-500 shadow-md shadow-red-50' : 'bg-white border-gray-100 text-gray-400 hover:text-red-500'}`}
            >
              <Heart fill={isFav ? "currentColor" : "none"} size={26} />
            </button>
          </div>

          <div className="mt-12 grid grid-cols-2 gap-4">
             <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
                <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Desarrollador</p>
                <p className="font-bold text-gray-900">{product.features.developer || 'N/A'}</p>
             </div>
             <div className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
                <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Año de Lanzamiento</p>
                <p className="font-bold text-gray-900">{product.features.year || 'N/A'}</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

