             <div className="p-6 bg-gray-50 rounded-[32px] border border-gray-100">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Disponibilidad</p>
                <p className={`font-black text-lg ${product.stock > 0 ? 'text-green-500' : 'text-red-500'}`}>
                   {product.stock > 0 ? `${product.stock} Unid.` : 'Agotado'}
