             </div>
          </div>

          <div className="mt-8 flex gap-3 flex-wrap">
             {product.modes.map(mode => (
                <div key={mode} className="px-4 py-2 bg-white border border-gray-200 rounded-full text-xs font-bold text-gray-500 flex items-center gap-2">
