export interface User {
  id: number;
  firstName: string;
  lastName: string;
  username: string;
  email: string;
  role: 'admin' | 'customer';
  token?: string; 
}

export interface Product {
  id: number;
  title: string;
  slug: string;
  description: string;
  genres: string[];
  platforms: string[];
  modes: string[];
  type: 'game' | 'console' | 'accessory';
  priceUsd: number;
  priceBs: number;
