export const AdminDashboard: React.FC = () => {
  const { user } = useStore();
  const navigate = useNavigate();
  const [metrics, setMetrics] = useState<any>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [carousels, setCarousels] = useState<CarouselConfig[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'discounts' | 'home_setup'>('dashboard');

  // Modal State
  const [showAddModal, setShowAddModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [newProd, setNewProd] = useState<Partial<Product>>({
    title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10,
    description: '', genres: [], platforms: [], modes: [], images: []
  });

  const loadData = async () => {
    const [m, p, n, o, c] = await Promise.all([
      mockService.getMetrics(),
      mockService.getProducts(),
      mockService.getNotifications(),
      mockService.getOrders(),
      mockService.getCarousels()
    ]);
    setMetrics(m);
    setProducts(p);
    setNotifications(n);
    setOrders(o);
    setCarousels(c);
  };

  useEffect(() => {
    if (!user || user.role !== 'admin') {
      navigate('/login');
      return;
    }
    loadData();
  }, [user]);

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await mockService.addProduct(newProd);
      setShowAddModal(false);
      setNewProd({ title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10, description: '', genres: [], platforms: [], modes: [], images: [] });
      await loadData();
      alert("Producto agregado exitosamente.");
    } catch (err) {
      alert("Error al agregar producto.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const updateDiscount = async (id: number, discount: number) => {
    try {
      await mockService.updateProduct(id, { discount });
      await loadData();
    } catch (err) {
      alert("Error al actualizar descuento.");
    }
  };

  const handleCarouselTitleUpdate = async (id: number, title: string) => {
    try {
