      alert("Error al actualizar título del carrusel.");
    }
  };

  const handleToggleProductInCarousel = async (carouselId: number, productId: number) => {
    const carousel = carousels.find(c => c.id === carouselId);
    if (!carousel) return;

    let newProductIds = [...carousel.productIds];
    if (newProductIds.includes(productId)) {
      newProductIds = newProductIds.filter(id => id !== productId);
    } else {
      newProductIds.push(productId);
    }

    try {
      await mockService.updateCarousel(carouselId, { productIds: newProductIds });
      await loadData();
    } catch (err) {
      alert("Error al actualizar productos del carrusel.");
