export const Home: React.FC = () => {
  const [products1, setProducts1] = useState<Product[]>([]);
  const [products2, setProducts2] = useState<Product[]>([]);
  const [products3, setProducts3] = useState<Product[]>([]);
  const [carouselConfigs, setCarouselConfigs] = useState<CarouselConfig[]>([]);

  useEffect(() => {
    const fetchData = async () => {
      const configs = await mockService.getCarousels();
      setCarouselConfigs(configs);

      const allProducts = await mockService.getProducts();

      const carousel1 = configs.find(c => c.id === 1);
      const carousel2 = configs.find(c => c.id === 2);
      const carousel3 = configs.find(c => c.id === 3);

      if (carousel1) setProducts1(allProducts.filter(p => carousel1.productIds.includes(p.id)));
      if (carousel2) setProducts2(allProducts.filter(p => carousel2.productIds.includes(p.id)));
      if (carousel3) setProducts3(allProducts.filter(p => carousel3.productIds.includes(p.id)));
    };
    fetchData();
  }, []);

  return (
    <div className="min-h-screen pb-20 bg-white">
      <HeroCarousel />

      {carouselConfigs[0] && (
        <ProductCarousel 
          title={carouselConfigs[0].title} 
          subtitle={carouselConfigs[0].subtitle} 
          products={products1} 
          icon={Star} 
        />
      )}

      {carouselConfigs[1] && (
        <div className="bg-gray-50/50 py-4">
          <ProductCarousel 
            title={carouselConfigs[1].title} 
            subtitle={carouselConfigs[1].subtitle} 
            products={products2} 
            icon={Tag} 
          />
        </div>
      )}

      {carouselConfigs[2] && (
        <ProductCarousel 
          title={carouselConfigs[2].title} 
          subtitle={carouselConfigs[2].subtitle} 
          products={products3} 
          icon={Clock} 
        />
      )}
    </div>
  );
};

