                  <input 
                    type="text" 
                    placeholder="¿Qué buscas hoy?..." 
                    value={search} 
                    onChange={e => setSearch(e.target.value)} 
                    className="w-full pl-10 pr-4 py-4 bg-gray-50 border border-gray-100 rounded-3xl outline-none focus:ring-2 focus:ring-[#6A00FF] transition-all shadow-sm font-medium" 
                  />
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={18} />
              </div>
           </div>

           {/* 2. Categoría (Cuadrilla 2x2) */}
           <div className="space-y-4">
              <h4 className="font-black text-[10px] uppercase tracking-[0.2em] text-gray-400">Categoría</h4>
              <div className="grid grid-cols-2 gap-3">
                {categories.map((cat) => {
                  const Icon = cat.icon;
                  const isActive = type === cat.id;
                  return (
                    <button 
                      key={cat.id}
                      onClick={() => setType(cat.id)}
                      className={`flex flex-col items-center justify-center p-4 rounded-3xl border-2 transition-all gap-2 ${
                        isActive 
                        ? 'bg-[#6A00FF] border-[#6A00FF] text-white shadow-lg shadow-purple-200' 
                        : 'bg-white border-gray-50 text-gray-400 hover:border-purple-100 hover:text-gray-600'
                      }`}
                    >
                      <Icon size={24} />
                      <span className="text-[10px] font-black uppercase tracking-wider">{cat.name}</span>
                    </button>
                  );
                })}
              </div>
           </div>

           {/* 3. Precio Máximo */}
           <div className="space-y-4 bg-gray-50 p-6 rounded-[32px] border border-gray-100">
              <div className="flex justify-between items-center">
                <h4 className="font-black text-[10px] uppercase tracking-[0.2em] text-gray-400">Precio Máximo</h4>
                <span className="text-sm font-black text-[#6A00FF]">${maxPrice}</span>
