  </span>
);

/**
 * Archivo: pages/AdminDashboard.tsx
 * Propósito: Gestión completa de inventario, pedidos, descuentos y personalización de la Home
 */
import React, { useEffect, useState } from 'react';
import { useStore } from '../context/StoreContext';
import { mockService } from '../services/mockService';
import { Product, Notification, Order, CarouselConfig } from '../types';
import { useNavigate } from 'react-router-dom';
import { 
  Package, Users, ChartBar, CircleAlert, Bell, ShoppingBag, 
  Eye, Plus, X, Tag, Percent, Save, Trash2, Home, Layout, 
  Edit3, CheckSquare, Square, Search, Layers, Type, Subtitles,
  ChevronRight, Calendar, CreditCard
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const AdminDashboard: React.FC = () => {
  const { user } = useStore();
  const navigate = useNavigate();
  const [metrics, setMetrics] = useState<any>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [carousels, setCarousels] = useState<CarouselConfig[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'discounts' | 'home_setup'>('dashboard');

  // Modals State
  const [showAddModal, setShowAddModal] = useState(false);
  const [showSelectionModal, setShowSelectionModal] = useState(false);
  const [editingCarousel, setEditingCarousel] = useState<CarouselConfig | null>(null);
  const [modalSearch, setModalSearch] = useState('');

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [newProd, setNewProd] = useState<Partial<Product>>({
    title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10,
    description: '', genres: [], platforms: [], modes: [], images: []
  });

  const loadData = async () => {
    const [m, p, o, c] = await Promise.all([
      mockService.getMetrics(),
      mockService.getProducts(),
      mockService.getOrders(),
      mockService.getCarousels()
    ]);
    setMetrics(m);
    setProducts(p);
    setOrders(o);
    setCarousels(c);
  };

  useEffect(() => {
    if (!user || user.role !== 'admin') {
      navigate('/login');
      return;
    }
    loadData();
  }, [user]);

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await mockService.addProduct(newProd);
      setShowAddModal(false);
      setNewProd({ title: '', priceUsd: 0, discount: 0, type: 'game', stock: 10, description: '', genres: [], platforms: [], modes: [], images: [] });
      await loadData();
    } finally {
      setIsSubmitting(false);
    }
  };

  const updateDiscount = async (id: number, discount: number) => {
    await mockService.updateProduct(id, { discount });
    await loadData();
  };

  const handleCarouselUpdate = async (id: number, data: Partial<CarouselConfig>) => {
    await mockService.updateCarousel(id, data);
    await loadData();
  };

  const handleToggleInModal = async (productId: number) => {
    if (!editingCarousel) return;
    let newIds = [...editingCarousel.productIds];
    if (newIds.includes(productId)) {
      newIds = newIds.filter(id => id !== productId);
    } else {
      newIds.push(productId);
    }
    const updated = { ...editingCarousel, productIds: newIds };
    setEditingCarousel(updated);
    await handleCarouselUpdate(editingCarousel.id, { productIds: newIds });
  };

  if (!metrics) return <div className="min-h-screen flex items-center justify-center text-gray-900 font-bold">Iniciando sistemas...</div>;

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 pb-20">
      <div className="max-w-7xl mx-auto px-4 py-8">

        {/* Navigation Tabs */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 bg-gray-900 rounded-2xl flex items-center justify-center text-[#6A00FF]">
                  <Layout size={28}/>
               </div>
               <h1 className="text-3xl font-black text-gray-900">Admin <span className="text-[#6A00FF]">Central</span></h1>
            </div>
            <div className="flex bg-white rounded-2xl p-1.5 border border-gray-100 shadow-xl overflow-x-auto max-w-full no-scrollbar">
                {[
                  { id: 'dashboard', label: 'Resumen' },
                  { id: 'orders', label: 'Pedidos' },
                  { id: 'products', label: 'Inventario' },
                  { id: 'discounts', label: 'Ofertas' },
                  { id: 'home_setup', label: 'Config. Inicio' }
                ].map((tab) => (
                  <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)} 
                    className={`px-8 py-3 rounded-xl text-sm font-black transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-[#6A00FF] text-white shadow-lg shadow-purple-200' : 'text-gray-400 hover:text-gray-600 hover:bg-gray-50'}`}
                  >
                    {tab.label}
                  </button>
                ))}
            </div>
        </div>

        {/* --- VIEWS --- */}

        {activeTab === 'dashboard' && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
            <MetricCard title="Productos" val={metrics.totalProducts} icon={Package} color="bg-purple-100 text-[#6A00FF]" />
            <MetricCard title="Usuarios" val={metrics.totalUsers} icon={Users} color="bg-blue-100 text-blue-600" />
            <MetricCard title="Ventas Mes" val={`$${metrics.monthlySales}`} icon={ChartBar} color="bg-green-100 text-green-600" />
            <MetricCard title="Stock Bajo" val={metrics.lowStock} icon={CircleAlert} color="bg-red-100 text-red-600" />
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
             <div className="p-8 border-b border-gray-50">
                <h2 className="font-black text-2xl text-gray-900">Registro de Pedidos</h2>
                <p className="text-gray-400 text-sm font-medium">Gestiona las ventas y estados de envío</p>
             </div>
             <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 text-gray-400 uppercase text-[10px] font-black tracking-widest">
                    <tr>
                      <th className="px-8 py-5">ID Pedido</th>
                      <th className="px-8 py-5">Cliente</th>
                      <th className="px-8 py-5">Fecha</th>
                      <th className="px-8 py-5">Total</th>
                      <th className="px-8 py-5">Estado</th>
                      <th className="px-8 py-5 text-right">Detalles</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {orders.length > 0 ? orders.map(order => (
                      <tr key={order.id} className="hover:bg-gray-50/50 transition-colors">
                        <td className="px-8 py-5 font-black text-gray-400">#{order.id}</td>
                        <td className="px-8 py-5 font-black text-gray-900">Usuario Demo</td>
                        <td className="px-8 py-5">
                          <div className="flex items-center gap-2 text-gray-500 text-sm font-medium">
                             <Calendar size={14}/> {new Date(order.createdAt).toLocaleDateString()}
                          </div>
                        </td>
                        <td className="px-8 py-5">
                          <div className="font-black text-gray-900">${order.totalUsd.toFixed(2)}</div>
                          <div className="text-[10px] text-gray-400 font-bold">Bs {order.totalBs.toFixed(2)}</div>
                        </td>
                        <td className="px-8 py-5">
                           <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${
                             order.status === 'paid' ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'
                           }`}>
                             {order.status}
                           </span>
                        </td>
                        <td className="px-8 py-5 text-right">
                           <button className="p-2 bg-gray-100 rounded-xl text-gray-400 hover:text-[#6A00FF] transition-all"><Eye size={18}/></button>
                        </td>
                      </tr>
                    )) : (
                      <tr>
                        <td colSpan={6} className="px-8 py-20 text-center">
                           <ShoppingBag className="mx-auto text-gray-100 mb-4" size={48}/>
                           <p className="text-gray-400 font-bold uppercase text-xs tracking-widest">No hay pedidos registrados</p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
             </div>
          </div>
        )}

        {activeTab === 'products' && (
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
            <div className="p-8 border-b border-gray-50 flex justify-between items-center">
              <div>
                <h2 className="font-black text-2xl text-gray-900">Control de Inventario</h2>
                <p className="text-gray-400 text-sm font-medium">Gestiona tu stock galáctico</p>
              </div>
              <button 
                onClick={() => setShowAddModal(true)}
                className="bg-[#6A00FF] text-white px-6 py-4 rounded-2xl flex items-center gap-2 font-black hover:bg-[#5b00db] transition-all shadow-lg shadow-purple-100 active:scale-95"
              >
                <Plus size={20}/> Nuevo Articulo
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50 text-gray-400 uppercase text-[10px] font-black tracking-widest">
                  <tr>
                    <th className="px-8 py-5">Producto</th>
                    <th className="px-8 py-5">Tipo</th>
                    <th className="px-8 py-5">Precio</th>
                    <th className="px-8 py-5">Stock</th>
                    <th className="px-8 py-5 text-right">Acciones</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="px-8 py-5 flex items-center gap-4">
                        <img src={p.images[0]} className="w-12 h-12 rounded-xl object-cover border-2 border-white shadow-sm" />
                        <span className="font-black text-gray-900">{p.title}</span>
                      </td>
                      <td className="px-8 py-5">
                         <span className="text-xs font-black uppercase text-gray-400 bg-gray-100 px-3 py-1 rounded-full">{p.type}</span>
                      </td>
                      <td className="px-8 py-5 font-black text-gray-900">${p.priceUsd}</td>
                      <td className="px-8 py-5">
                        <div className={`text-sm font-black flex items-center gap-2 ${p.stock <= 5 ? 'text-red-500' : 'text-green-500'}`}>
                           <div className={`w-1.5 h-1.5 rounded-full ${p.stock <= 5 ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`} />
                           {p.stock} Unid.
                        </div>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <button className="text-[#6A00FF] font-black text-xs hover:underline mr-6">EDITAR</button>
                        <button 
                          onClick={async () => { if(confirm('¿Eliminar?')) { await mockService.deleteProduct(p.id); loadData(); } }}
                          className="text-red-400 hover:text-red-600 transition-colors"
                        >
                          <Trash2 size={20}/>
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'discounts' && (
          <div className="space-y-8">
            <div className="bg-[#6A00FF] p-10 rounded-[40px] text-white shadow-2xl relative overflow-hidden">
                <Tag className="absolute right-[-40px] top-[-40px] w-64 h-64 opacity-10 rotate-12" />
                <h2 className="text-4xl font-black mb-2 tracking-tighter">Ofertas Galácticas</h2>
                <p className="opacity-80 text-lg font-medium">Configura descuentos masivos para atraer a más pilotos.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.map(p => (
                <div key={p.id} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-6 group hover:shadow-xl transition-all">
                  <img src={p.images[0]} className="w-20 h-20 rounded-2xl object-cover shadow-md group-hover:scale-110 transition-transform" />
                  <div className="flex-1">
                    <h4 className="font-black text-gray-900 mb-2 leading-tight">{p.title}</h4>
                    <div className="flex items-center gap-3">
                       <span className="text-[10px] font-black text-gray-300 uppercase">Dto:</span>
                       <div className="relative">
                          <input 
                            type="number" 
                            min="0" max="90"
                            defaultValue={p.discount || 0}
                            onBlur={(e) => updateDiscount(p.id, parseInt(e.target.value) || 0)}
                            className="w-20 px-4 py-2 bg-gray-50 border-2 border-transparent focus:border-[#6A00FF] rounded-xl text-sm font-black text-[#6A00FF] outline-none transition-all"
                          />
                          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-[#6A00FF] font-black text-xs">%</span>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'home_setup' && (
          <div className="space-y-12">
            <div className="bg-gray-900 p-12 rounded-[48px] text-white shadow-2xl relative overflow-hidden">
                <Layout className="absolute right-[-40px] top-[-40px] w-80 h-80 opacity-5" />
                <div className="relative z-10">
                   <h2 className="text-5xl font-black mb-4 tracking-tighter">Escaparate <span className="text-[#6A00FF]">Principal</span></h2>
                   <p className="opacity-60 text-xl font-medium max-w-2xl">Controla cada palabra y producto que aparece en tu terminal de inicio.</p>
                </div>
            </div>

            <div className="space-y-16">
              {carousels.map((carousel, idx) => (
                <div key={carousel.id} className="bg-white rounded-[40px] border border-gray-100 shadow-2xl overflow-hidden">
                  {/* Header Seccion */}
                  <div className="bg-gray-50/50 px-10 py-8 border-b border-gray-50 flex justify-between items-center">
                    <div className="flex items-center gap-5">
                      <div className="bg-gray-900 text-[#6A00FF] w-14 h-14 rounded-2xl flex items-center justify-center text-2xl font-black shadow-lg shadow-purple-100">
                        {idx + 1}
                      </div>
                      <div>
                        <h3 className="text-2xl font-black text-gray-900">Carrusel {idx + 1}</h3>
                        <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">{carousel.productIds.length} Items activos</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => { setEditingCarousel(carousel); setShowSelectionModal(true); setModalSearch(''); }}
                      className="bg-[#6A00FF] text-white px-8 py-4 rounded-2xl font-black flex items-center gap-3 hover:bg-[#5b00db] transition-all shadow-xl shadow-purple-100 active:scale-95"
                    >
                      <Plus size={20}/> Seleccionar Productos
                    </button>
                  </div>

                  <div className="p-10 grid grid-cols-1 lg:grid-cols-2 gap-12">
                    {/* Columna Izquierda: Edicion de Texto */}
                    <div className="space-y-8">
                       <div className="space-y-3">
                          <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#6A00FF] flex items-center gap-2">
                            <Type size={14}/> Título Principal
                          </label>
                          <input 
                            type="text" 
                            defaultValue={carousel.title}
                            onBlur={(e) => handleCarouselUpdate(carousel.id, { title: e.target.value })}
                            className="w-full bg-white border-2 border-gray-100 rounded-2xl px-6 py-5 text-xl font-black text-gray-900 outline-none focus:border-[#6A00FF] transition-all shadow-sm"
                            placeholder="Ej: Lo más jugado"
                          />
                       </div>

                       <div className="space-y-3">
                          <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#6A00FF] flex items-center gap-2">
                            <Subtitles size={14}/> Subtítulo o Descripción
                          </label>
                          <input 
                            type="text" 
                            defaultValue={carousel.subtitle}
                            onBlur={(e) => handleCarouselUpdate(carousel.id, { subtitle: e.target.value })}
                            className="w-full bg-white border-2 border-gray-100 rounded-2xl px-6 py-5 text-lg font-bold text-gray-500 outline-none focus:border-[#6A00FF] transition-all shadow-sm"
                            placeholder="Ej: Favoritos de la comunidad"
                          />
                       </div>
                    </div>

                    {/* Columna Derecha: Vista previa de productos actuales */}
                    <div className="space-y-4">
                        <label className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Vista Previa de Selección</label>
                        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                           {products.filter(p => carousel.productIds.includes(p.id)).length > 0 ? (
                             products.filter(p => carousel.productIds.includes(p.id)).map(p => (
                               <div key={p.id} className="relative group overflow-hidden rounded-2xl aspect-[3/4] border-2 border-gray-50 shadow-sm">
                                  <img src={p.images[0]} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                                  <div className="absolute inset-0 bg-gradient-to-t from-gray-900/80 to-transparent flex items-end p-3">
                                     <p className="text-white text-[10px] font-black uppercase truncate">{p.title}</p>
                                  </div>
                               </div>
                             ))
                           ) : (
                             <div className="col-span-full py-12 flex flex-col items-center justify-center border-2 border-dashed border-gray-100 rounded-[32px] bg-gray-50/50">
                                <Layers className="text-gray-200 mb-2" size={32} />
                                <p className="text-gray-300 font-bold text-xs uppercase">Sin productos seleccionados</p>
                             </div>
                           )}
                        </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>

      {/* --- SELECTION MODAL --- */}
      <AnimatePresence>
        {showSelectionModal && editingCarousel && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowSelectionModal(false)}
              className="absolute inset-0 bg-gray-900/95 backdrop-blur-md"
            />
            <motion.div 
              initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
              className="relative bg-white w-full max-w-5xl rounded-[48px] shadow-2xl overflow-hidden flex flex-col h-[85vh]"
            >
              <div className="p-10 bg-white border-b border-gray-50 flex justify-between items-center">
                <div>
                   <h2 className="text-3xl font-black text-gray-900">Seleccionar Productos</h2>
                   <p className="text-gray-400 font-bold uppercase text-xs tracking-widest mt-1">Gestionando: {editingCarousel.title}</p>
                </div>
                <button onClick={() => setShowSelectionModal(false)} className="w-14 h-14 bg-gray-50 rounded-full flex items-center justify-center text-gray-400 hover:bg-red-50 hover:text-red-500 transition-all"><X size={24}/></button>
              </div>

              <div className="px-10 py-6 bg-gray-50/50">
                 <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Buscar por título en el inventario..." 
                      value={modalSearch}
                      onChange={e => setModalSearch(e.target.value)}
                      className="w-full pl-14 pr-6 py-5 bg-white border-2 border-transparent focus:border-[#6A00FF] rounded-3xl outline-none shadow-sm font-black text-lg transition-all"
                    />
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-300" size={24} />
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-10 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 scroll-smooth no-scrollbar">
                 {products.filter(p => p.title.toLowerCase().includes(modalSearch.toLowerCase())).map(p => {
                    const isSelected = editingCarousel.productIds.includes(p.id);
                    return (
                      <button 
                        key={p.id}
                        onClick={() => handleToggleInModal(p.id)}
                        className={`relative flex flex-col p-4 rounded-[32px] border-2 transition-all text-left group ${
                          isSelected 
                          ? 'bg-purple-50 border-[#6A00FF] shadow-lg shadow-purple-100' 
                          : 'bg-white border-gray-50 hover:border-gray-100 opacity-60 grayscale-[0.5]'
                        }`}
                      >
                         <div className="relative aspect-square rounded-2xl overflow-hidden mb-4 shadow-sm">
                            <img src={p.images[0]} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                            {isSelected && (
                              <div className="absolute top-2 right-2 bg-[#6A00FF] text-white p-2 rounded-xl shadow-lg"><CheckSquare size={16} strokeWidth={3} /></div>
                            )}
                         </div>
                         <div className="px-1">
                            <p className={`font-black text-sm truncate ${isSelected ? 'text-[#6A00FF]' : 'text-gray-900'}`}>{p.title}</p>
                            <p className="text-[10px] font-black text-gray-300 uppercase tracking-tighter mt-1">{p.type} • ${p.priceUsd}</p>
                         </div>
                      </button>
                    )
                 })}
              </div>

              <div className="p-8 border-t border-gray-50 bg-white flex justify-between items-center">
                 <div className="bg-[#6A00FF] text-white px-4 py-2 rounded-xl font-black text-sm">{editingCarousel.productIds.length} SELECCIONADOS</div>
                 <button onClick={() => setShowSelectionModal(false)} className="bg-gray-900 text-white px-12 py-4 rounded-2xl font-black text-lg hover:bg-black transition-all shadow-xl active:scale-95">Finalizar Gestión</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* --- ADD PRODUCT MODAL --- */}
      <AnimatePresence>
        {showAddModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setShowAddModal(false)} className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
            <motion.div initial={{ scale: 0.9, y: 20, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.9, y: 20, opacity: 0 }} className="relative bg-white w-full max-w-3xl rounded-[40px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-8 bg-[#6A00FF] text-white flex justify-between items-center">
                <h2 className="text-2xl font-black flex items-center gap-3"><Plus size={28}/> Nuevo Artículo</h2>
                <button onClick={() => setShowAddModal(false)} className="hover:rotate-90 transition-transform"><X size={24}/></button>
              </div>
              <form onSubmit={handleAddProduct} className="p-10 overflow-y-auto space-y-8 no-scrollbar">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Título del Producto</label>
                      <input required type="text" value={newProd.title} onChange={e => setNewProd({...newProd, title: e.target.value})} className="w-full bg-gray-50 border-2 border-transparent focus:border-[#6A00FF] p-4 rounded-2xl outline-none font-black text-lg" placeholder="Elden Ring..." />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio USD</label>
                        <input required type="number" step="0.01" value={newProd.priceUsd} onChange={e => setNewProd({...newProd, priceUsd: parseFloat(e.target.value)})} className="w-full bg-gray-50 p-4 rounded-2xl outline-none font-black" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Dto %</label>
                        <input type="number" value={newProd.discount} onChange={e => setNewProd({...newProd, discount: parseInt(e.target.value)})} className="w-full bg-gray-50 p-4 rounded-2xl outline-none font-black text-[#6A00FF]" />
                      </div>
                    </div>
                  </div>
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Categoría</label>
                      <select value={newProd.type} onChange={e => setNewProd({...newProd, type: e.target.value as any})} className="w-full bg-gray-50 p-4 rounded-2xl outline-none font-black appearance-none">
