        {/* --- VIEWS --- */}

        {activeTab === 'dashboard' && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
            <MetricCard title="Productos" val={metrics.totalProducts} icon={Package} color="bg-purple-100 text-[#6A00FF]" />
