const MetricCard = ({ title, val, icon: Icon, color }: any) => (
  <div className="bg-white p-8 rounded-[32px] shadow-sm border border-gray-50 flex items-center gap-6 hover:shadow-xl transition-all group">
    <div className={`p-4 rounded-2xl group-hover:scale-110 transition-transform ${color}`}><Icon size={32} /></div>
    <div><p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">{title}</p><p className="text-3xl font-black text-gray-900">{val}</p></div>
  </div>
);

/**
 * Archivo: types.ts
 * Propósito: Definiciones de tipos TypeScript
 */

export interface User {
  id: number;
  firstName: string;
  lastName: string;
  username: string;
  email: string;
  phone: string; // Nuevo campo
  role: 'admin' | 'customer';
  token?: string; 
}

export interface Product {
  id: number;
  title: string;
  slug: string;
  description: string;
  genres: string[];
  platforms: string[];
  modes: string[];
  type: 'game' | 'console' | 'accessory';
  priceUsd: number;
  priceBs: number;
  discount?: number; // Porcentaje de descuento (0-100)
  stock: number;
  images: string[];
  features: Record<string, string>;
  status: 'active' | 'inactive';
  salesCount: number;
  createdAt: string;
}

export interface CartItem {
  productId: number;
  qty: number;
  product: Product;
}

export interface Order {
  id: number;
  userId: number;
  items: CartItem[];
  totalUsd: number;
  totalBs: number;
  status: 'pending' | 'paid' | 'confirmed' | 'delivered' | 'cancelled';
  paymentMethod?: string;
  paymentRef?: string;
  paymentScreenshot?: string;
  createdAt: string;
}

export interface Notification {
  id: number;
  type: 'low_stock' | 'new_order' | 'new_faq';
  message: string;
  read: boolean;
  timestamp: string;
