           </div>

           <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Username</label>
              <input required name="username" onChange={handleChange} placeholder="Inventa un nombre divertido ¡Sé creativoo!" className="w-full bg-gray-50 px-4 py-3 rounded-xl border-2 border-transparent focus:border-[#6A00FF] outline-none font-bold placeholder-gray-400 text-sm text-gray-900" />
           </div>

           <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Teléfono</label>
                <input required name="phone" type="tel" onChange={handleChange} className="w-full bg-gray-50 px-4 py-3 rounded-xl border-2 border-transparent focus:border-[#6A00FF] outline-none font-bold text-gray-900" />
