                        </div>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <div className="flex justify-end items-center gap-2">
                          <button 
                            onClick={() => openEditModal(p)}
                            className="p-2 text-[#6A00FF] hover:bg-purple-50 rounded-lg transition-colors"
